package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"io"
	"log"
	"sort"

	"go.skia.org/infra/go/util"
	"go.skia.org/infra/task_scheduler/go/docker/config"
	"go.skia.org/infra/task_scheduler/go/specs"
)

const (
	// STATIC indicates that an artifact is not generated by a task but
	// generated elsewhere and pinned to a specific sha256 in the config.
	STATIC = "<static>"
)

func main() {
	flag.Parse()

	// Parse the config file.
	var cfg *config.Config
	if err := util.WithReadFile(flag.Arg(0), func(r io.Reader) error {
		var err error
		cfg, err = config.Parse(r)
		return err
	}); err != nil {
		log.Fatal(err)
	}

	// Convert the config file to the Task Scheduler format.

	// Mapping of artifact name to the task which generates it.
	artifacts := map[string]string{}
	for name := range cfg.Images {
		artifacts[name] = STATIC
	}
	for name, task := range cfg.Tasks {
		if task.DockerBuild != nil {
			for artifact := range task.DockerBuild.Outputs {
				if exist, ok := artifacts[artifact]; ok {
					log.Fatalf("Only one task may generate %q; found %s and %s", artifact, exist, name)
				}
				artifacts[artifact] = name
			}
		}
	}

	// The "output" TasksCfg.
	tasksCfg := &specs.TasksCfg{
		Tasks: map[string]*specs.TaskSpec{},
		Jobs:  map[string]*specs.JobSpec{},
	}
	addDependencyForArtifact := func(spec *specs.TaskSpec, artifact string) {
		task, ok := artifacts[artifact]
		if !ok {
			log.Fatalf("Artifact %q not defined in images section or as output of any task!", artifact)
		}
		if task != STATIC {
			spec.Dependencies = append(spec.Dependencies, task)
		}
	}
	for name, task := range cfg.Tasks {
		spec := &specs.TaskSpec{}

		// Only one type of task is allowed.
		found := false
		if task.DockerBuild != nil {
			found = true
			spec.Isolate = task.DockerBuild.File // TODO(borenet): Need an isolate file for this Dockerfile.
			addDependencyForArtifact(spec, task.DockerBuild.Base)
			spec.Command = []string{"docker", "build", "-f", task.DockerBuild.File} // TODO(borenet): This is a canned task driver.
			for k, v := range task.DockerBuild.BuildArgs {
				spec.Command = append(spec.Command, "--build-arg", fmt.Sprintf("%s=%s", k, v))
			}
		} else if task.DockerRun != nil {
			if found {
				log.Fatalf("Only one definition allowed per task! %s", name)
			}
			found = true
			addDependencyForArtifact(spec, task.DockerRun.Image)
			for artifact := range task.DockerRun.Artifacts {
				addDependencyForArtifact(spec, artifact)
			}
			// TODO(borenet): Use the sha256 sum for the image; this would be done
			// inside the task driver.
			spec.Command = append([]string{"docker", "run", task.DockerRun.Image, "--"}, task.DockerRun.Command...)
			spec.Isolate = "fake-isolate-for-docker-run"
		} else if task.RawCmd != nil {
			if found {
				log.Fatalf("Only one definition allowed per task! %s", name)
			}
			found = true
			spec.Command = task.RawCmd.Command
			spec.Isolate = "fake-isolate-for-raw-cmd"
		}
		if !found {
			log.Fatalf("No task definition for %s", name)
		}
		sort.Strings(spec.Dependencies)

		// Dimensions.
		for k, v := range task.Dimensions {
			spec.Dimensions = append(spec.Dimensions, fmt.Sprintf("%s:%s", k, v))
		}
		sort.Strings(spec.Dimensions)

		tasksCfg.Tasks[name] = spec
	}

	for name, job := range cfg.Jobs {
		spec := &specs.JobSpec{}
		spec.TaskSpecs = job.Tasks
		spec.Trigger = job.Trigger
		tasksCfg.Jobs[name] = spec
	}

	if err := tasksCfg.Validate(); err != nil {
		log.Fatal(err)
	}

	if err := util.WithWriteFile(flag.Arg(1), func(w io.Writer) error {
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(tasksCfg)
	}); err != nil {
		log.Fatal(err)
	}
}
